text:
Use packages to group related definitions.

package Example {
  part def Vehicle;
}

Define a reusable part with `part def` and instances with `part`.

part def Sensor {
  attribute id: String;
}

part sensor1 : Sensor;

Requirements capture constraints with id/text.

requirement ReqA {
  id = "REQ-001";
  text = "The system shall ...";
}

State  describe lifecycle behavior.

state Lifecycle {
  state Idle;
  state Active;
  transition start from Idle to Active;
}

Use alias import to shorten qualified names.

import AliasImport::Definitions::Vehicle;
part vehicle : Vehicle;

Interfaces define contracts between parts.

interface def Power {
  attribute voltage: Real;
}

Associations connect parts.

association def Connects {
  end a: PartA;
  end b: PartB;
}

Constraints capture invariants.

constraint def TempLimit {
  attribute maxTemp: Real;
}

state def S {
  state off;
  state on {
    do providePower;
  }

  transition off_to_on
    first off
    accept OnSignal
    then on;

  transition on_to_off
    first on
    accept OffSignal
    then off;
}
